const engine = msg.payload;
let variance = 1.0;
if (engine.status === "Warning") variance = 1.20;
else if (engine.status === "Critical") variance = 1.45;

const baseFeatures = [0.12, 0.08, 0.15, 0.10, 0.05, 0.03, 0.40, 0.22, 0.18, 0.09, 0.11, 0.07, 0.02, 0.14];
let simulatedFeatures = baseFeatures.map(f => {
    let noise = (Math.random() * 0.04) - 0.02;
    return parseFloat(Math.max(0, (f * variance) + noise).toFixed(4));
});

let egt = parseFloat((370 + Math.random() * 130 * variance).toFixed(2));
let vib = parseFloat((1.0 + Math.random() * 3.8 * variance).toFixed(2));

msg.payload = {
    engineId: String(engine.id || "UNKNOWN"),
    engineName: String(engine.nom || "N/A"),
    engineStatus: String(engine.status || "En service"),
    timestamp: new Date().toISOString(),
    egtTemperature: egt,
    engineVibration: vib,
    features: simulatedFeatures
};
msg.engineName = msg.payload.engineName; msg.engineId = msg.payload.engineId;
return msg;

let engineId = msg.engineId;
let buffer = context.get("sensorBuffer_" + engineId) || [];

buffer.push(msg.payload.features);
if (buffer.length > 30) {
    buffer.shift();
}
context.set("sensorBuffer_" + engineId, buffer);

if (buffer.length === 30) {
    msg.payload = { window: buffer };
    return msg;
} else {
    return null;
}
